      "duration": 0.5
    },
    {
      "keystrokes": "git ls-tree -r --name-only ORIG_HEAD || true\n",
      "duration": 0.5
    },
    {
      "keystrokes": "sh -c 'for f in $(git ls-tree -r --name-only ORIG_HEAD 2>/dev/null); do git show ORIG_HEAD:\"$f\" | grep -a -n \"secret\\[\" && echo \"-- in $f\"; done || true'\n",
      "duration": 1.0
    },
    {
      "keystrokes": "git log --oneline --decorate\n",
      "duration": 0.5
    },
    {
      "keystrokes": "git show 09fc438:README.md || true\n",
      "duration": 0.5
    },
    {
      "keystrokes": "git show 80188ed:README.md || true\n",
      "duration": 0.5
    },
    {
      "keystrokes": "sh -c 'git grep -a -h -o \"secret\\[[^]]*\\]\" $(git rev-list --all) | head -n 1 > /app/secret.txt || true'\n",
      "duration": 1.0
    },
    {
      "keystrokes": "cat /app/secret.txt\n",
      "duration": 0.1
    },
    {
      "keystrokes": "sh -c 'git cat-file --batch-all-objects --batch-check | awk \"{print \\$1,\\$2}\" | while read oid type; do git cat-file -p \"$oid\" | grep -a -o \"secret\\[[^]]*\\]\" && echo \" in $oid ($type)\"; done | head -n 1 | sed -E \"s/(secret\\[[^]]*\\]).*/\\1/\" > /app/secret.txt'\n",
      "duration": 2.0
    },
    {
      "keystrokes": "cat /app/secret.txt\n",
      "duration": 0.1
    },
    {
      "keystrokes": "git rev-parse --verify -q refs/stash || echo \"no stash\"\n",
      "duration": 0.3
    },
    {
      "keystrokes": "sh -c 'git show -s --format=%B $(cat .git/ORIG_HEAD 2>/dev/null) 2>/dev/null | grep -a -o \"secret\\[[^]]*\\]\" | head -n 1 > /app/secret.txt || true'\n",
      "duration": 0.5
    },
    {
      "keystrokes": "cat /app/secret.txt\n",
      "duration": 0.1
    },
    {
      "keystrokes": "sh -c 'if [ -s /app/secret.txt ]; then echo \"Recovered secret:\" && cat /app/secret.txt; else echo \"Secret not found yet\"; fi'\n",
      "duration": 0.1
    },
    {
      "keystrokes": "sh -c 'git grep -a -n \"secret\\[\" $(git rev-list --all) || true'\n",
      "duration": 1.0
    },
    {
      "keystrokes": "sh -c 'git cat-file --batch-all-objects --batch-check | awk \"{print \\$1,\\$2}\" | while read oid type; do if git cat-file -p \"$oid\" | grep -a -q \"secret\\[\"; then echo \"Found in $oid ($type)\"; fi; done || true'\n",
      "duration": 2.0
    }
  ]
}

